/* 2) Padrões que ajudam a evitar bugs */

*,
*::before,
*::after {
  box-sizing: border-box;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* 3) Layout base com gap (mais previsível) */
.stack {
  display: grid;
  gap: 16px;
}
